// ✅ VALIDACIÓN REAL SIN LIBRERÍAS EXTERNAS
try {
  const { email, password } = $json.body;

  // Validación básica
  if (!email || !password) {
    return {
      success: false,
      error: 'Email y contraseña son requeridos',
      statusCode: 400
    };
  }

  // Validar formato de email con regex nativo
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) {
    return {
      success: false,
      error: 'Formato de email inválido',
      statusCode: 400
    };
  }

  // Rate limiting básico con timestamp
  const clientIP = $json.headers['x-forwarded-for'] || 'unknown';
  const rateLimitKey = `rate_limit_${clientIP}`;

  return {
    email: email.toLowerCase().trim(),
    password,
    clientIP,
    userAgent: $json.headers['user-agent'] || 'unknown',
    timestamp: new Date().toISOString()
  };

} catch (error) {
  return {
    success: false,
    error: 'Error validando entrada',
    statusCode: 500
  };
}

// ✅ PROCESAR RESPUESTA DE SUPABASE
try {
  const authResponse = $json;

  if (authResponse.error) {
    return {
      success: false,
      error: authResponse.error_description || 'Credenciales inválidas',
      statusCode: 401
    };
  }

  // Supabase devuelve el token directamente
  const { access_token, refresh_token, user } = authResponse;

  if (!access_token || !user) {
    return {
      success: false,
      error: 'Error en respuesta de autenticación',
      statusCode: 500
    };
  }

  // Obtener datos adicionales del usuario desde nuestra BD
  return {
    success: true,
    user: {
      id: user.id,
      email: user.email,
      role: user.user_metadata?.role || 'vendedor',
      company_id: user.user_metadata?.company_id || 1,
      profile: user.user_metadata?.profile || {}
    },
    tokens: {
      accessToken: access_token,
      refreshToken: refresh_token
    },
    expiresIn: authResponse.expires_in
  };

} catch (error) {
  return {
    success: false,
    error: 'Error procesando autenticación',
    statusCode: 500
  };
}

// ✅ VALIDAR JWT CON SUPABASE
try {
  const authHeader = $json.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return {
      success: false,
      error: 'Token de autorización requerido',
      statusCode: 401
    };
  }

  const token = authHeader.substring(7);

  // Validar token con Supabase
  return {
    token,
    saleData: $json.body,
    clientIP: $json.headers['x-forwarded-for'] || 'unknown',
    userAgent: $json.headers['user-agent'] || 'unknown'
  };

} catch (error) {
  return {
    success: false,
    error: 'Error validando token',
    statusCode: 500
  };
}

// ✅ PROCESAR VENTA CON VALIDACIÓN ROBUSTA
try {
  const products = $('📦 Verificar Inventario Seguro').all().map(item => item.json);
  const saleData = $json.saleData;
  const user = $json.user;

  // ✅ VALIDACIÓN ROBUSTA DE DATOS DE ENTRADA

  // Validar estructura básica
  if (!saleData || typeof saleData !== 'object') {
    throw new Error('saleData debe ser un objeto válido');
  }

  // Validar items
  if (!saleData.items || !Array.isArray(saleData.items) || saleData.items.length === 0) {
    throw new Error('items debe ser un array no vacío');
  }

  // Validar cada item individualmente
  for (let i = 0; i < saleData.items.length; i++) {
    const item = saleData.items[i];

    // Validar product_id
    if (!Number.isInteger(item.product_id) || item.product_id <= 0) {
      throw new Error(`Item ${i}: product_id inválido: ${item.product_id}. Debe ser un entero positivo.`);
    }

    // Validar quantity
    if (!Number.isInteger(item.quantity) || item.quantity <= 0) {
      throw new Error(`Item ${i}: quantity inválida: ${item.quantity}. Debe ser un entero positivo.`);
    }

    // Validar unit_price
    if (typeof item.unit_price !== 'number' || item.unit_price <= 0 || !isFinite(item.unit_price)) {
      throw new Error(`Item ${i}: unit_price inválido: ${item.unit_price}. Debe ser un número positivo finito.`);
    }
  }

  // Validar customer_info
  if (!saleData.customer_info || typeof saleData.customer_info !== 'object') {
    throw new Error('customer_info es requerido y debe ser un objeto');
  }

  if (!saleData.customer_info.name || typeof saleData.customer_info.name !== 'string' || saleData.customer_info.name.trim() === '') {
    throw new Error('customer_info.name es requerido y no puede estar vacío');
  }

  // Validar email si se proporciona
  if (saleData.customer_info.email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(saleData.customer_info.email)) {
      throw new Error('customer_info.email tiene formato inválido');
    }
  }

  // Validar payment_method
  const validPaymentMethods = ['cash', 'card', 'transfer', 'check'];
  if (saleData.payment_method && !validPaymentMethods.includes(saleData.payment_method)) {
    throw new Error(`payment_method inválido: ${saleData.payment_method}. Valores válidos: ${validPaymentMethods.join(', ')}`);
  }

  // ✅ VERIFICAR INVENTARIO
  const inventoryCheck = {};
  for (const product of products) {
    inventoryCheck[product.id] = {
      available: product.quantity - product.reserved,
      product: product
    };
  }

  const unavailableItems = [];
  let totalAmount = 0;

  for (const item of saleData.items) {
    const inventory = inventoryCheck[item.product_id];
    if (!inventory || inventory.available < item.quantity) {
      unavailableItems.push({
        product_id: item.product_id,
        requested: item.quantity,
        available: inventory ? inventory.available : 0,
        product_name: inventory ? inventory.product.name : 'No encontrado'
      });
    }

    totalAmount += item.quantity * item.unit_price;
  }

  if (unavailableItems.length > 0) {
    return {
      success: false,
      error: 'Inventario insuficiente',
      unavailableItems,
      statusCode: 400
    };
  }

  // ✅ CALCULAR TOTALES
  const taxRate = 0.16;
  const taxAmount = Math.round(totalAmount * taxRate * 100) / 100; // Redondear a 2 decimales
  const finalTotal = Math.round((totalAmount + taxAmount) * 100) / 100;

  // Generar número de factura único
  const timestamp = Date.now();
  const randomSuffix = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
  const invoiceNumber = `F-${new Date().getFullYear()}-${timestamp.toString().slice(-6)}-${randomSuffix}`;

  return {
    company_id: user.user_metadata?.company_id || 1,
    user_id: user.id,
    customer_info: {
      name: saleData.customer_info.name.trim(),
      email: saleData.customer_info.email?.trim() || null,
      phone: saleData.customer_info.phone?.trim() || null
    },
    invoice_number: invoiceNumber,
    total_amount: totalAmount,
    tax_amount: taxAmount,
    final_total: finalTotal,
    payment_method: saleData.payment_method || 'cash',
    items: saleData.items,
    metadata: {
      ip: $json.clientIP,
      user_agent: $json.userAgent,
      timestamp: new Date().toISOString(),
      validation_passed: true
    }
  };

} catch (error) {
  return {
    success: false,
    error: error.message || 'Error procesando venta',
    statusCode: 400,
    validation_error: true
  };
}

// Validar token JWT
try {
  const authHeader = $json.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return {
      success: false,
      error: 'Token de autorización requerido',
      statusCode: 401
    };
  }

  const token = authHeader.substring(7);

  return {
    token,
    query: $json.query,
    clientIP: $json.headers['x-forwarded-for'] || 'unknown'
  };

} catch (error) {
  return {
    success: false,
    error: 'Error validando token',
    statusCode: 500
  };
}

// ✅ HEALTH CHECK REAL
try {
  const dbHealth = $('🗄️ PostgreSQL - Health Check').first().json;
  const redisHealth = $('⚡ Redis - Health Check').first().json;

  const overallStatus = (dbHealth && redisHealth) ? 'healthy' : 'unhealthy';

  return {
    status: overallStatus,
    timestamp: new Date().toISOString(),
    services: {
      database: {
        status: dbHealth ? 'healthy' : 'unhealthy'
      },
      redis: {
        status: redisHealth ? 'healthy' : 'unhealthy'
      }
    },
    version: '1.0.0'
  };

} catch (error) {
  return {
    status: 'unhealthy',
    timestamp: new Date().toISOString(),
    error: error.message
  };
}
